// ✅ Fix: Add with explicit size limits
const express = require('express');
const app = express();

app.use(express.json({ limit: '10kb' }));
app.use(express.urlencoded({ extended: false, limit: '10kb' }));
```

#### 2. No Security Headers (OWASP A05: Security Misconfiguration)
The app sets no HTTP security headers, leaving it vulnerable to clickjacking, MIME sniffing, XSS, and more.

```js
// ✅ Fix: Add helmet for security headers
const helmet = require('helmet');
app.use(helmet());

// This sets: Content-Security-Policy, X-Content-Type-Options,
// X-Frame-Options, Strict-Transport-Security, X-XSS-Protection, etc.
```

#### 3. No Rate Limiting (OWASP A04: Insecure Design)
Any endpoint is freely accessible with no rate limiting, enabling brute-force and DoS attacks.

```js
// ✅ Fix: Add rate limiting
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
});

app.use(limiter);
```

---

### 🟠 High-Severity Issues

#### 4. No Authentication or Authorization (OWASP A01: Broken Access Control)
The `/users` endpoint returns user PII (names and emails) with **zero authentication**. This is an information disclosure vulnerability.

```js
// ❌ Current: anyone can access user data
app.get('/users', (req, res) => {
  res.json([...]);
});

// ✅ Fix: Add authentication middleware
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  try {
    const user = jwt.verify(token, process.env.JWT_SECRET);
    req.user = user;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

app.get('/users', authenticateToken, (req, res) => {
  // Return only non-sensitive fields
  res.json(users.map(({ id, name }) => ({ id, name })));
});
```

#### 5. PII Exposure in API Response (OWASP A01: Broken Access Control)
Even with authentication, exposing raw email addresses in API responses should be avoided unless explicitly needed.

```js
// ❌ Current: exposes email directly
{ id: 1, name: 'Alice', email: 'alice@example.com' }

// ✅ Fix: Use response DTOs / field filtering
const sanitizeUser = ({ id, name }) => ({ id, name });

app.get('/users', authenticateToken, (req, res) => {
  res.json(users.map(sanitizeUser));
});
```

#### 6. No CORS Configuration (OWASP A05: Security Misconfiguration)
Without explicit CORS, the default behavior varies. You should define an explicit allowlist.

```js
// ✅ Fix: Explicit CORS configuration
const cors = require('cors');

app.use(cors({
  origin: ['https://yourdomain.com'],
  methods: ['GET'],
  allowedHeaders: ['Content-Type', 'Authorization'],
}));
```

---

### 🟡 Medium-Severity Issues

#### 7. Express Server Fingerprinting
Express sends `X-Powered-By: Express` by default, leaking server technology to attackers.

```js
// ✅ Fix: Disable the header
app.disable('x-powered-by');
// (helmet also does this automatically)
```

#### 8. Listening on All Interfaces
`app.listen(3000)` binds to `0.0.0.0` by default, making the server accessible on all network interfaces.

```js
// ❌ Current: binds to all interfaces
app.listen(3000);

// ✅ Fix: Bind to localhost if not public-facing
app.listen(3000, '127.0.0.1', () => {
  console.log('Server running on localhost:3000');
});
```

#### 9. Hardcoded Port (OWASP A05: Security Misconfiguration)
The port is hardcoded, preventing environment-based configuration.

```js
// ✅ Fix: Use environment variable with fallback
const PORT = parseInt(process.env.PORT, 10) || 3000;
app.listen(PORT, '127.0.0.1', () => {
  console.log(`Server running on port ${PORT}`);
});
```

#### 10. No Error Handling Middleware
Missing global error handler means unhandled errors could leak stack traces to clients.

```js
// ✅ Fix: Add global error handler (MUST be after all routes)
app.use((err, req, res, next) => {
  console.error(err.stack); // Log full error server-side
  res.status(500).json({ error: 'Internal server error' }); // Return generic message
});
```

#### 11. No Request Logging / Audit Trail
No logging means no way to detect or investigate attacks.

```js
// ✅ Fix: Add structured request logging
const morgan = require('morgan');
app.use(morgan('combined')); // or use a structured logger like pino/winston
```

---

### 🟢 Low-Severity / Best Practices

#### 12. No `404` Handler
Missing routes return Express's default HTML error, which leaks framework info.

```js
// ✅ Fix: Add explicit 404 handler before error handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});
```

#### 13. No Graceful Shutdown
Abrupt shutdown can leave connections in a bad state.

```js
// ✅ Fix: Handle SIGTERM gracefully
const server = app.listen(PORT, '127.0.0.1');

process.on('SIGTERM', () => {
  console.log('SIGTERM received. Shutting down gracefully...');
  server.close(() => process.exit(0));
});
```

