app.get('/users', (req, res) => {
  res.json([
    { id: 1, name: 'Alice', email: 'alice@example.com' },
    { id: 2, name: 'Bob', email: 'bob@example.com' },
  ]);
});
```

**Recommendation:** Add authentication middleware and restrict access:

```js
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];
  if (!token) return res.status(401).json({ error: 'Authentication required' });

  try {
    const user = jwt.verify(token, process.env.JWT_SECRET);
    req.user = user;
    next();
  } catch (err) {
    return res.status(403).json({ error: 'Invalid or expired token' });
  }
};

app.get('/users', authenticateToken, (req, res) => {
  // ... return users
});
```

---

### 2. No Security Headers (`helmet` missing) — OWASP A05:2021 Security Misconfiguration

The app sets **no security-related HTTP headers**. This leaves it vulnerable to clickjacking, MIME sniffing, XSS in older browsers, and more. Express also sends `X-Powered-By: Express` by default, which is an information leak.

**Recommendation:**

```js
const helmet = require('helmet');
app.use(helmet());   // Sets ~15 security headers in one line

// At minimum, disable the X-Powered-By header:
app.disable('x-powered-by');
```

---

### 3. No Rate Limiting — Denial of Service Risk

Both endpoints can be called unlimited times. An attacker could easily overwhelm the server. Related to **OWASP A04:2021 – Insecure Design**.

**Recommendation:**

```js
const rateLimit = require('express-rate-limit');

const limiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,                  // limit each IP to 100 requests per window
  standardHeaders: true,
  legacyHeaders: false,
  message: { error: 'Too many requests, please try again later.' },
});

app.use(limiter);
```

